def init_if_empty():
    db = SessionLocal()
    try:
        count = db.query(PriceTable).count()
        if count > 0:
            print(f"db has {count} records, skip")
            return
        for item in seed_data:
            db.add(item)
        db.commit()
        print(f"seeded {len(seed_data)} records")
    except Exception as e:
        db.rollback()
        print(f"seed error: {e}")
    finally:
        db.close()


def init():
    init_if_empty()


if __name__ == "__main__":
    init()